<span class="line"><span style="color:#C678DD;">  return</span><span style="color:#61AFEF;"> postfix</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;great&#39;</span><span style="color:#ABB2BF;">)</span></span>
